// ============ API : Génération de facture PROFORMA Échange (PDF, format template) ============
// Reproduit la mise en page du template "ECHANGE PORT TAXES" en PDF (pdf-lib, pur JS),
// logo + signature embarqués. Les charges = uniquement les lignes reçues dans p.lines.
const { isLicenseActive } = require('./license.js');

const LOGO_B64 = "";
const SIGN_B64 = "";

function num(v){ var n = parseFloat(String(v == null ? '' : v).replace(/[^\d.\-]/g, '')); return isNaN(n) ? 0 : n; }
function money(n){ n = Math.round(Number(n) || 0); var neg = n < 0; var s = String(Math.abs(n)); var out = ''; while (s.length > 3){ out = ' ' + s.slice(-3) + out; s = s.slice(0, -3); } return (neg ? '-' : '') + s + out; }
function pdfSafe(s){
  return String(s == null ? '' : s)
    .replace(/[\u2018\u2019\u201A\u201B]/g, "'").replace(/[\u201C\u201D\u201E]/g, '"')
    .replace(/[\u2013\u2014]/g, '-').replace(/\u2026/g, '...').replace(/\u00A0/g, ' ')
    .replace(/[^\x00-\xFF]/g, '?');
}
function wrap(str, maxW, f, size){
  str = pdfSafe(str); var words = str.split(/\s+/); var lines = []; var cur = '';
  words.forEach(function(w){
    var t = cur ? cur + ' ' + w : w;
    if (f.widthOfTextAtSize(t, size) <= maxW) { cur = t; return; }
    if (cur) lines.push(cur);
    if (f.widthOfTextAtSize(w, size) > maxW){ var s = w; while (s.length){ var k = s.length; while (k > 1 && f.widthOfTextAtSize(s.slice(0, k), size) > maxW) k--; lines.push(s.slice(0, k)); s = s.slice(k); } cur = ''; }
    else cur = w;
  });
  if (cur) lines.push(cur);
  return lines.length ? lines : [''];
}

async function buildProformaPdf(p){
  const { PDFDocument, StandardFonts, rgb } = require('pdf-lib');
  const doc = await PDFDocument.create();
  const font = await doc.embedFont(StandardFonts.Helvetica);
  const bold = await doc.embedFont(StandardFonts.HelveticaBold);
  const ital = await doc.embedFont(StandardFonts.HelveticaOblique);
  var logoImg = null, signImg = null;
  try { logoImg = await doc.embedPng(Buffer.from(LOGO_B64, 'base64')); } catch(e){}
  try { signImg = await doc.embedPng(Buffer.from(SIGN_B64, 'base64')); } catch(e){}

  const blue = rgb(0.11, 0.31, 0.55);        // bandeaux
  const blueDark = rgb(0.08, 0.24, 0.44);
  const dark = rgb(0.13, 0.13, 0.13);
  const fillLt = rgb(0.90, 0.93, 0.97);      // remplissage clair (remplace le beige)
  const fillHdr = rgb(0.82, 0.88, 0.95);
  const border = rgb(0.55, 0.60, 0.67);
  const white = rgb(1, 1, 1);

  const W = 595.28, H = 841.89;
  let page = doc.addPage([W, H]);
  const X0 = 28, X1 = 567;

  function box(x, y, w, h, fill){
    if (fill) page.drawRectangle({ x: x, y: y - h, width: w, height: h, color: fill });
    page.drawRectangle({ x: x, y: y - h, width: w, height: h, borderColor: border, borderWidth: 0.6 });
  }
  function cell(x, y, w, h, text, opt){
    opt = opt || {};
    var size = opt.size || 8.5, f = opt.font || font, col = opt.color || dark, align = opt.align || 'l', pad = (opt.pad == null ? 4 : opt.pad);
    var s = pdfSafe(text == null ? '' : String(text));
    if (opt.maxW && f.widthOfTextAtSize(s, size) > opt.maxW){ var lines = wrap(s, opt.maxW, f, size); s = lines[0]; }
    var tw = f.widthOfTextAtSize(s, size);
    var tx = align === 'c' ? x + (w - tw) / 2 : (align === 'r' ? x + w - tw - pad : x + pad);
    var ty = y - h / 2 - size / 2 + 1.5;
    page.drawText(s, { x: tx, y: ty, size: size, font: f, color: col });
  }
  function txt(x, y, text, size, f, col){ page.drawText(pdfSafe(text), { x: x, y: y, size: size || 8.5, font: f || font, color: col || dark }); }

  let y = H - 26;

  // ===== 1) Logo + grille en-tête =====
  var h1 = 78;
  box(X0, y, 150, h1, null);
  if (logoImg){ var lw = 92, lh = lw * logoImg.height / logoImg.width; page.drawImage(logoImg, { x: X0 + (150 - lw) / 2, y: y - (h1 + lh) / 2, width: lw, height: lh }); }
  var gx = 300, gw = X1 - gx;             // grille droite
  box(gx, y, gw, 24, fillLt); cell(gx, y, gw, 24, p.transitaire || '', { align: 'c', font: bold, size: 9.5 });
  var lbl = 118;
  box(gx, y - 24, lbl, 18, fillLt); cell(gx, y - 24, lbl, 18, 'Business Partner', { font: bold, size: 8, align: 'c' });
  box(gx + lbl, y - 24, gw - lbl, 18, null); cell(gx + lbl, y - 24, gw - lbl, 18, p.bp || '', { size: 9 });
  box(gx, y - 42, lbl, 18, fillLt); cell(gx, y - 42, lbl, 18, 'Contract Account', { font: bold, size: 8, align: 'c' });
  box(gx + lbl, y - 42, gw - lbl, 18, null); cell(gx + lbl, y - 42, gw - lbl, 18, p.contractAcc || '', { size: 9 });
  box(gx, y - 60, lbl, 18, fillLt); cell(gx, y - 60, lbl, 18, 'Company code', { font: bold, size: 8, align: 'c' });
  box(gx + lbl, y - 60, gw - lbl, 18, null); cell(gx + lbl, y - 60, gw - lbl, 18, p.companyCode || 'CI12', { size: 9, align: 'c', font: bold });
  y -= h1;

  // ===== 2) Bandeau titre =====
  var hT = 18; page.drawRectangle({ x: X0, y: y - hT, width: X1 - X0, height: hT, color: blue });
  cell(X0, y, X1 - X0, hT, 'FACTURE PROFORMA ' + (p.type || 'ECHANGE'), { align: 'c', font: bold, size: 10, color: white });
  y -= hT;

  // ===== 3) Vessel/Voyage + désignation + conteneurs + marchandise (+ MONTANT EN XOF) =====
  var leftR = 455;                        // séparation avec la colonne MONTANT
  var rr = 15;                            // hauteur de ligne
  var topBlock = y;
  // Vessel / Voyage
  box(X0, y, 140, rr, null); cell(X0, y, 140, rr, 'Vessel Name', { font: bold, size: 8.5 });
  box(X0 + 140, y, leftR - X0 - 140, rr, fillLt); cell(X0 + 140, y, leftR - X0 - 140, rr, p.vessel || '', { size: 9 }); y -= rr;
  box(X0, y, 140, rr, null); cell(X0, y, 140, rr, 'Voyage Number', { font: bold, size: 8.5 });
  box(X0 + 140, y, leftR - X0 - 140, rr, fillLt); cell(X0 + 140, y, leftR - X0 - 140, rr, p.voyage || '', { size: 9 }); y -= rr;
  // Désignation
  var hD = 18; box(X0, y, leftR - X0, hD, null); cell(X0, y, leftR - X0, hD, 'DESIGNATION DES RUBRIQUES FACTUREES', { align: 'c', font: bold, size: 9 }); y -= hD;
  // Conteneurs : Taille / Quantité / Type sur 3 colonnes
  var cLab = 120, c1 = X0 + cLab, cw = (leftR - c1) / 3;
  function crow(label, v1, v2, v3, fill, fnt){
    box(X0, y, cLab, rr, null); cell(X0, y, cLab, rr, label, { font: bold, size: 8.5 });
    box(c1, y, cw, rr, fill); cell(c1, y, cw, rr, v1, { align: 'c', size: 8.5, font: fnt });
    box(c1 + cw, y, cw, rr, fill); cell(c1 + cw, y, cw, rr, v2, { align: 'c', size: 8.5, font: fnt });
    box(c1 + 2 * cw, y, cw, rr, fill); cell(c1 + 2 * cw, y, cw, rr, v3, { align: 'c', size: 8.5, font: fnt });
    y -= rr;
  }
  crow('Taille Conteneur', "40'", "20'", "40'", null, bold);
  crow('Quantite', String(num(p.c40frigo)), String(num(p.c20sec)), String(num(p.c40sec)), fillLt, font);
  crow('Type', 'FRIGO', 'SEC', 'SEC', null, font);
  // Marchandise + Code M/se
  box(X0, y, cLab, rr, null); cell(X0, y, cLab, rr, 'Marchandise', { font: bold, size: 8.5 });
  box(c1, y, 150, rr, fillLt); cell(c1, y, 150, rr, p.commodityName || '', { size: 8.5, maxW: 146 });
  box(c1 + 150, y, 70, rr, null); cell(c1 + 150, y, 70, rr, 'Code M/se', { font: bold, size: 8, align: 'c' });
  box(c1 + 220, y, leftR - (c1 + 220), rr, fillLt); cell(c1 + 220, y, leftR - (c1 + 220), rr, p.commodityCode || '', { size: 8.5, align: 'c' }); y -= rr;
  // Livraison
  box(X0, y, cLab, rr, null); cell(X0, y, cLab, rr, 'Livraison', { font: bold, size: 8.5 });
  box(c1, y, leftR - c1, rr, fillLt); cell(c1, y, leftR - c1, rr, p.deliveryZone || '', { size: 8.5 }); y -= rr;
  // Colonne MONTANT EN XOF (spanne tout le bloc)
  box(leftR, topBlock, X1 - leftR, topBlock - y, null);
  cell(leftR, topBlock, X1 - leftR, topBlock - y, 'MONTANT EN XOF', { align: 'c', font: bold, size: 9, color: blueDark });

  // ===== 4) Footer external billing =====
  var hF = 16; box(X0, y, X1 - X0, hF, null); cell(X0, y, X1 - X0, hF, p.footer || '', { size: 7.5, maxW: X1 - X0 - 8, font: bold }); y -= hF;

  // ===== 5) Date / UBLI / Type / Client =====
  var dc = [ { t: 'Date de facturation', x: X0, w: 137 }, { t: 'UBLI', x: X0 + 137, w: 135 }, { t: 'Type', x: X0 + 272, w: 80 }, { t: 'Client', x: X0 + 352, w: X1 - (X0 + 352) } ];
  var hDh = 15;
  dc.forEach(function(c){ page.drawRectangle({ x: c.x, y: y - hDh, width: c.w, height: hDh, color: blue }); page.drawRectangle({ x: c.x, y: y - hDh, width: c.w, height: hDh, borderColor: border, borderWidth: 0.6 }); cell(c.x, y, c.w, hDh, c.t, { align: 'c', font: bold, size: 8, color: white }); });
  y -= hDh;
  var today = new Date().toLocaleDateString('fr-FR');
  var dvals = [today, p.ubli || '', p.type || 'ECHANGE', p.client || ''];
  dc.forEach(function(c, i){ box(c.x, y, c.w, hDh, null); cell(c.x, y, c.w, hDh, dvals[i], { align: 'c', size: 8.5, maxW: c.w - 6 }); });
  y -= hDh + 8;

  // ===== 6) Tableau des charges =====
  var cols = [
    { t: 'Description', x: X0, w: 180, a: 'l' },
    { t: 'Base',        x: X0 + 180, w: 42, a: 'c' },
    { t: 'Unite',       x: X0 + 222, w: 42, a: 'c' },
    { t: 'Taux',        x: X0 + 264, w: 58, a: 'r' },
    { t: 'Montant HT',  x: X0 + 322, w: 60, a: 'r' },
    { t: 'TVA',         x: X0 + 382, w: 32, a: 'c' },
    { t: 'Montant TVA', x: X0 + 414, w: 63, a: 'r' },
    { t: 'Montant TTC', x: X0 + 477, w: X1 - (X0 + 477), a: 'r' }
  ];
  var hHdr = 26;
  cols.forEach(function(c){ page.drawRectangle({ x: c.x, y: y - hHdr, width: c.w, height: hHdr, color: fillHdr }); page.drawRectangle({ x: c.x, y: y - hHdr, width: c.w, height: hHdr, borderColor: border, borderWidth: 0.6 }); var ls = wrap(c.t, c.w - 4, bold, 8); var yy = y - hHdr / 2 - (ls.length * 9) / 2 + 8; ls.forEach(function(l){ var tw = bold.widthOfTextAtSize(l, 8); page.drawText(l, { x: c.x + (c.w - tw) / 2, y: yy, size: 8, font: bold, color: dark }); yy -= 9; }); });
  y -= hHdr;

  var lines = Array.isArray(p.lines) ? p.lines : [];
  var total = 0;
  for (var i = 0; i < lines.length; i++){
    var l = lines[i] || {};
    var qty = num(l.qty), rate = num(l.rate), vat = (l.vat ? 1 : 0);
    var ht = qty * rate, tva = vat ? Math.round(ht * 0.18) : 0, ttc = ht + tva;
    total += ttc;
    var descLines = wrap(l.desc || '', cols[0].w - 8, font, 8);
    var rowH = Math.max(15, descLines.length * 9.5 + 5);
    if (y - rowH < 120){ page = doc.addPage([W, H]); y = H - 40; }
    cols.forEach(function(c){ box(c.x, y, c.w, rowH, null); });
    var ty = y - 11;
    descLines.forEach(function(dl){ txt(cols[0].x + 4, ty, dl, 8, font, dark); ty -= 9.5; });
    cell(cols[1].x, y, cols[1].w, rowH, l.unit || '', { align: 'c', size: 8 });
    cell(cols[2].x, y, cols[2].w, rowH, String(qty), { align: 'c', size: 8 });
    cell(cols[3].x, y, cols[3].w, rowH, money(rate), { align: 'r', size: 8 });
    cell(cols[4].x, y, cols[4].w, rowH, money(ht), { align: 'r', size: 8 });
    cell(cols[5].x, y, cols[5].w, rowH, vat ? '1' : '-', { align: 'c', size: 8 });
    cell(cols[6].x, y, cols[6].w, rowH, vat ? money(tva) : '-', { align: 'r', size: 8 });
    cell(cols[7].x, y, cols[7].w, rowH, money(ttc), { align: 'r', size: 8 });
    y -= rowH;
  }

  // ===== Total =====
  var hTot = 24;
  if (y - hTot < 110){ page = doc.addPage([W, H]); y = H - 40; }
  var totW = cols[7].x - X0;
  box(X0, y, totW, hTot, fillLt); cell(X0, y, totW, hTot, 'ARRETE LA PRESENTE FACTURE PROFORMA A VOTRE DEBIT POUR FCFA TTC', { font: ital, size: 8, color: blueDark });
  box(cols[7].x, y, cols[7].w, hTot, fillHdr); cell(cols[7].x, y, cols[7].w, hTot, money(total), { align: 'r', font: bold, size: 10, color: blueDark });
  y -= hTot + 14;

  // ===== Signature =====
  if (signImg){
    var sw = 150, sh = sw * signImg.height / signImg.width;
    if (y - sh - 14 < 30){ page = doc.addPage([W, H]); y = H - 40; }
    txt(X1 - sw, y, 'Signature / Cachet :', 8, bold, dark);
    page.drawImage(signImg, { x: X1 - sw, y: y - sh - 6, width: sw, height: sh });
  }

  return await doc.save();
}

function safeName(s){ return String(s || '').replace(/[^A-Za-z0-9_\-]/g, '_').slice(0, 40); }

module.exports = async (req, res) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'POST, GET, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') { res.status(200).end(); return; }
  if (req.method === 'GET') {
    var diag = { ok: true, node: process.version, format: 'pdf', logo: !!(LOGO_B64 && LOGO_B64.length > 20), sign: !!(SIGN_B64 && SIGN_B64.length > 20) };
    try { require('pdf-lib'); diag.pdflib = true; } catch (e) { diag.pdflib = false; diag.pdflibErr = e.message; }
    res.status(200).json(diag); return;
  }
  if (req.method !== 'POST') { res.status(405).json({ ok: false, error: 'POST uniquement' }); return; }
  var active = false;
  try { active = await isLicenseActive(); } catch (e) { active = false; }
  if (!active) { res.status(403).json({ ok: false, blocked: true, error: 'Licence inactive' }); return; }
  try {
    let body = req.body;
    if (typeof body === 'string') { try { body = JSON.parse(body); } catch (e) { body = {}; } }
    const p = (body && body.proforma) || body || {};
    const bytes = await buildProformaPdf(p);
    const b64 = Buffer.from(bytes).toString('base64');
    const fname = 'Proforma_' + (safeName(p.bl) || safeName(p.ubli) || safeName(p.client) || 'echange') + '.pdf';
    res.status(200).json({ ok: true, b64: b64, filename: fname, mime: 'application/pdf' });
  } catch (e) {
    res.status(200).json({ ok: false, error: 'Erreur génération proforma : ' + e.message });
  }
};
